import { createClient } from "@/lib/supabase/server";
import { redirect, notFound } from "next/navigation";
import Link from "next/link";
import type { Metadata } from "next";
import type {
  PatientRow,
  MedicalRecordRow,
  SessionRow,
  PaymentRow,
} from "@/types/database";
import { PatientDetailTabs } from "@/components/dashboard/PatientDetailTabs";
import { formatDate } from "@/lib/utils";

export const metadata: Metadata = { title: "Detalhe do Paciente" };

// ── Status config ─────────────────────────────────────────────────
const STATUS_CONFIG: Record<
  string,
  { label: string; badgeClass: string; dotClass: string }
> = {
  new: {
    label: "Novo",
    badgeClass: "border-[#38bdf8]/40 bg-[#38bdf8]/10 text-[#38bdf8]",
    dotClass: "bg-[#38bdf8] shadow-[0_0_8px_#38bdf8]",
  },
  active: {
    label: "Ativo",
    badgeClass:
      "border-[rgba(82,183,136,.4)] bg-[rgba(82,183,136,.12)] text-[var(--color-brand)]",
    dotClass: "bg-[var(--color-brand)] shadow-[0_0_8px_var(--color-brand)]",
  },
  inactive: {
    label: "Inativo",
    badgeClass:
      "border-[var(--color-border-strong)] bg-[var(--color-surface-hover)] text-[var(--color-text-muted)]",
    dotClass: "bg-[var(--color-text-muted)]",
  },
  lead: {
    label: "Lead",
    badgeClass: "border-[#fbbf24]/40 bg-[#fbbf24]/10 text-[#fbbf24]",
    dotClass: "bg-[#fbbf24] shadow-[0_0_8px_#fbbf24]",
  },
  archived: {
    label: "Arquivado",
    badgeClass:
      "border-[var(--color-border-strong)] bg-[var(--color-surface-hover)] text-[var(--color-text-muted)]",
    dotClass: "bg-[var(--color-text-muted)]",
  },
};

function initials(name: string): string {
  const parts = name.trim().split(/\s+/);
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
  return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
}

// ── Data fetching ─────────────────────────────────────────────────
async function getPatientDetail(therapistId: string, patientId: string) {
  const supabase = await createClient();

  const [patientResult, recordsResult, sessionsResult, paymentsResult] =
    await Promise.all([
      supabase
        .from("patients")
        .select("*")
        .eq("id", patientId)
        .eq("therapist_id", therapistId)
        .single(),

      supabase
        .from("medical_records")
        .select("*")
        .eq("patient_id", patientId)
        .eq("therapist_id", therapistId)
        .order("created_at", { ascending: false }),

      supabase
        .from("sessions")
        .select("*")
        .eq("patient_id", patientId)
        .eq("therapist_id", therapistId)
        .order("created_at", { ascending: false }),

      supabase
        .from("payments")
        .select("*")
        .eq("patient_id", patientId)
        .eq("therapist_id", therapistId)
        .order("created_at", { ascending: false }),
    ]);

  return {
    patient: patientResult.data as unknown as PatientRow | null,
    records: (recordsResult.data ?? []) as unknown as MedicalRecordRow[],
    sessions: (sessionsResult.data ?? []) as unknown as SessionRow[],
    payments: (paymentsResult.data ?? []) as unknown as PaymentRow[],
  };
}

// ── Page ──────────────────────────────────────────────────────────
export default async function PatientDetailPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;

  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) redirect("/auth/login");

  const { data: therapist } = await supabase
    .from("therapists")
    .select("id")
    .eq("user_id", user.id)
    .single();
  if (!therapist) redirect("/auth/login");

  const { patient, records, sessions, payments } = await getPatientDetail(
    therapist.id,
    id
  );
  if (!patient) notFound();

  const statusCfg = STATUS_CONFIG[patient.status] ?? STATUS_CONFIG.inactive;

  return (
    <div className="p-8 max-w-6xl mx-auto animate-[fadeUp_.4s_ease-out_both] w-full">
      {/* Back link */}
      <Link
        href="/dashboard/pacientes"
        className="inline-flex items-center gap-1.5 text-[13px] text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] mb-5 transition-colors duration-200"
      >
        ← Voltar para pacientes
      </Link>

      {/* Patient header */}
      <div className="flex gap-6 items-start mb-8">
        {/* Avatar */}
        <div className="w-20 h-20 rounded-full shrink-0 bg-[radial-gradient(circle_at_35%_35%,_rgba(82,183,136,0.25),_rgba(82,183,136,0.05))] border-[1.5px] border-[var(--color-brand)]/40 flex items-center justify-center font-[family-name:var(--font-display)] text-[28px] text-[var(--color-brand)] font-light shadow-inner">
          {initials(patient.name)}
        </div>

        {/* Patient info */}
        <div className="flex-1">
          <div className="flex items-center gap-4 mb-2">
            <h1 className="font-[family-name:var(--font-display)] text-4xl font-light text-[var(--color-text-primary)] tracking-tight">
              {patient.name}
            </h1>
            <span
              className={`text-[12px] px-3 py-1 rounded-full border inline-flex items-center gap-2 font-medium ${statusCfg.badgeClass}`}
            >
              <span className={`w-1.5 h-1.5 rounded-full ${statusCfg.dotClass}`} />
              {statusCfg.label}
            </span>
          </div>

          {/* Contact details */}
          <div className="flex flex-wrap gap-4 text-[14px] text-[var(--color-text-muted)] font-light mb-2">
            <span className="flex items-center gap-1.5"><span className="opacity-70">✉</span> {patient.email}</span>
            {patient.phone && <span className="flex items-center gap-1.5"><span className="opacity-70">📞</span> {patient.phone}</span>}
            {patient.telegram_username && (
              <span className="text-sky-400 font-medium">
                @{patient.telegram_username}
              </span>
            )}
          </div>

          {/* Meta row */}
          <div className="flex flex-wrap gap-4 text-[13px] text-[var(--color-text-muted)] font-light">
            {patient.birth_date && (
              <span className="flex items-center gap-1.5"><span className="opacity-70">🎂</span> {formatDate(patient.birth_date)}</span>
            )}
            {patient.cpf && <span>CPF: {patient.cpf}</span>}
            <span>Desde {formatDate(patient.created_at)}</span>
            {patient.gdpr_consent && (
              <span className="text-[var(--color-brand)] font-medium">✓ LGPD consentido</span>
            )}
          </div>

          {/* Tags */}
          {patient.tags && patient.tags.length > 0 && (
            <div className="flex gap-2 mt-3 flex-wrap">
              {patient.tags.map((tag) => (
                <span
                  key={tag}
                  className="text-[12px] px-3 py-0.5 rounded-full bg-[var(--color-surface)] text-[var(--color-text-secondary)] border border-[var(--color-border-subtle)]"
                >
                  {tag}
                </span>
              ))}
            </div>
          )}

          {/* Mood */}
          {patient.mood_score !== null && patient.mood_score !== undefined && (
            <div className="flex gap-1.5 items-center mt-3">
              <span className="text-[13px] text-[var(--color-text-muted)] mr-1">
                Humor médio:
              </span>
              {[1, 2, 3, 4, 5].map((n) => (
                <div
                  key={n}
                  className={`w-2 h-2 rounded-full transition-colors duration-300 ${
                    n <= (patient.mood_score ?? 0)
                      ? "bg-[var(--color-brand)] shadow-[0_0_6px_var(--color-brand)]"
                      : "bg-[var(--color-border-strong)]"
                  }`}
                />
              ))}
              <span className="text-[12px] text-[var(--color-text-muted)] font-medium ml-1.5">
                {patient.mood_score}/5
              </span>
            </div>
          )}
        </div>

        {/* Actions */}
        <div className="flex gap-3 shrink-0">
          <button
            type="button"
            className="px-5 py-2.5 bg-[var(--color-surface)] text-[var(--color-text-secondary)] rounded-xl border border-[var(--color-border-subtle)] text-[14px] font-medium hover:bg-[var(--color-surface-hover)] hover:border-[var(--color-border-strong)] transition-all duration-300 shadow-sm"
          >
            Editar
          </button>
          <Link
            href={`/dashboard/agenda?patient=${id}`}
            className="px-5 py-2.5 bg-[var(--color-brand)] text-[#060E09] rounded-xl border border-transparent text-[14px] font-medium hover:bg-opacity-90 transition-all duration-300 shadow-[0_0_20px_rgba(82,183,136,0.2)] inline-flex items-center gap-2"
          >
            <span>+</span> Agendar Sessão
          </Link>
        </div>
      </div>

      {/* Stats row */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        <StatCard
          label="Sessões"
          value={String(sessions.length)}
          tone="brand"
          delay={0.05}
        />
        <StatCard
          label="Registros"
          value={String(records.length)}
          tone="sky"
          delay={0.1}
        />
        <StatCard
          label="Pagamentos"
          value={String(payments.length)}
          tone="amber"
          delay={0.15}
        />
        <StatCard
          label="NPS Médio"
          value={calcAvgNPS(sessions)}
          tone="violet"
          delay={0.2}
        />
      </div>

      {/* Tabs */}
      <div className="animate-[fadeUp_.4s_ease-out_.3s_both]">
        <PatientDetailTabs
          patientId={id}
          records={records}
          sessions={sessions}
          payments={payments}
        />
      </div>
    </div>
  );
}

// ── Helpers ───────────────────────────────────────────────────────
function StatCard({
  label,
  value,
  tone,
  delay = 0,
}: {
  label: string;
  value: string;
  tone: "brand" | "sky" | "amber" | "violet";
  delay?: number;
}) {
  const delayClass: Record<string, string> = {
    "0": "[animation-delay:0s]",
    "0.05": "[animation-delay:0.05s]",
    "0.1": "[animation-delay:0.1s]",
    "0.15": "[animation-delay:0.15s]",
    "0.2": "[animation-delay:0.2s]",
  };

  const toneClasses: Record<
    "brand" | "sky" | "amber" | "violet",
    { value: string; glow: string }
  > = {
    brand: {
      value: "text-[var(--color-brand)]",
      glow: "bg-[var(--color-brand)]",
    },
    sky: {
      value: "text-[#38bdf8]",
      glow: "bg-[#38bdf8]",
    },
    amber: {
      value: "text-[#fbbf24]",
      glow: "bg-[#fbbf24]",
    },
    violet: {
      value: "text-[#a78bfa]",
      glow: "bg-[#a78bfa]",
    },
  };

  const toneCfg = toneClasses[tone];

  return (
    <div
      className={`relative overflow-hidden bg-[var(--color-surface)] border border-[var(--color-border-subtle)] rounded-2xl p-5 hover:border-[var(--color-border-strong)] transition-colors glass-panel animate-[fadeUp_.4s_ease-out_both] ${delayClass[String(delay)] ?? ""}`}
    >
      <div className={`absolute right-0 top-0 h-24 w-24 rounded-bl-full opacity-[0.03] ${toneCfg.glow}`} />
      <div className="text-[12px] text-[var(--color-text-muted)] mb-2 uppercase tracking-widest font-medium">
        {label}
      </div>
      <div className={`font-[family-name:var(--font-display)] text-3xl font-light ${toneCfg.value}`}>
        {value}
      </div>
    </div>
  );
}

function calcAvgNPS(sessions: SessionRow[]): string {
  const scored = sessions.filter(
    (s) => s.nps_score !== null && s.nps_score !== undefined
  );
  if (scored.length === 0) return "—";
  const avg =
    scored.reduce((a, s) => a + (s.nps_score ?? 0), 0) / scored.length;
  return `${avg.toFixed(1)}/5`;
}
